app.get('/api/search', async (req, res) => {
  const { q, limit = 20, offset = 0, sort } = req.query
  if (!q) return res.status(400).json({ error: 'Query requerido' })

  let url = `https://api.mercadolibre.com/sites/MLC/search?q=${encodeURIComponent(q)}&limit=${limit}&offset=${offset}`
  if (sort === 'price_asc') url += '&sort=price_asc'
  if (sort === 'price_desc') url += '&sort=price_desc'

  const data = await fetchML(url)
  if (data && data.results?.length) {
    return res.json({ query: q, total: data.paging?.total || 0, offset: data.paging?.offset || 0, limit: data.paging?.limit || 20, products: data.results.map(formatProduct), source: 'live' })
  }

  const all = getSeedProducts(q)
  let products = all.map(formatProduct)
  if (sort === 'price_asc') products.sort((a, b) => a.price - b.price)
  if (sort === 'price_desc') products.sort((a, b) => b.price - a.price)
  const off = Number(offset)
  const lim = Number(limit)
  res.json({ query: q, total: products.length, offset: off, limit: lim, products: products.slice(off, off + lim), source: 'seed' })
})

app.get('/api/deals', async (req, res) => {
  const data = await fetchML('https://api.mercadolibre.com/sites/MLC/search?q=oferta+especial&sort=price_asc&limit=20')
  if (data && data.results?.length) {
    const products = data.results.filter(p => p.original_price && p.original_price > p.price).map(formatProduct)
    if (products.length) return res.json({ products, source: 'live' })
  }
  const products = SEED.filter(p => p.original_price > p.price).map(formatProduct)
  res.json({ products, source: 'seed' })
})

