app.get('/api/product/:id', async (req, res) => {
  const data = await fetchML(`https://api.mercadolibre.com/items/${req.params.id}`)
  if (data?.id) return res.json(formatProduct(data))
  const found = SEED.find(p => p.id === req.params.id)
  if (found) return res.json(formatProduct(found))
  res.status(404).json({ error: 'Producto no encontrado' })
})

